#Requires -Version 5.1
<#
.SYNOPSIS
    ADDetector launcher - entry point for ps2exe packaging.
.DESCRIPTION
    This script is what gets compiled into ADDetector.exe via ps2exe (with -noConsole).
    It locates MainForm.ps1 relative to itself and dot-sources it, so all .ps1/.psm1/
    .json files stay external (portable + transparent + editable).
#>

# Resolve our own directory whether running as .ps1 or as compiled .exe
$basePath = $null
if ($MyInvocation.MyCommand.Path) {
    $basePath = Split-Path -Parent $MyInvocation.MyCommand.Path
} elseif ($PSScriptRoot) {
    $basePath = $PSScriptRoot
} else {
    try {
        $basePath = Split-Path -Parent ([System.Reflection.Assembly]::GetEntryAssembly().Location)
    } catch {
        $basePath = (Get-Location).Path
    }
}

Set-Location -Path $basePath

# ── Log Setup ────────────────────────────────────────────────────────────────
$logDir  = Join-Path $basePath 'logs'
$logFile = Join-Path $logDir 'ADDetector.log'
if (-not (Test-Path $logDir)) { New-Item -ItemType Directory -Path $logDir -Force | Out-Null }

function Write-LaunchLog {
    param([string]$Level, [string]$Message)
    $line = "$(Get-Date -Format 'yyyy-MM-dd HH:mm:ss') [$Level] $Message"
    Add-Content -Path $logFile -Value $line -Encoding UTF8
}

# Log rotation: 7 gunden eski satirlari sil
try {
    if (Test-Path $logFile) {
        $cutoff  = (Get-Date).AddDays(-7).ToString('yyyy-MM-dd')
        $content = Get-Content $logFile -Encoding UTF8 -ErrorAction Stop
        $kept    = $content | Where-Object { $_ -match '^\d{4}-\d{2}-\d{2}' -and ($_ -replace '^(\d{4}-\d{2}-\d{2}).*','$1') -ge $cutoff }
        if ($kept) { Set-Content $logFile -Value $kept -Encoding UTF8 }
        else       { Clear-Content $logFile }
    }
} catch { }

Write-LaunchLog 'INFO' "ADDetector starting | basePath=$basePath"

# Embedded ICO (Base64) - set window icon without external file
$script:EmbeddedICO = ''

# ── Version + Auto-Update Check ─────────────────────────────────────────────
$script:CurrentVersion  = 'v1.1.0'
$script:UpdateAvailable = $false
$script:LatestVersion   = ''
$script:LatestZipUrl    = ''

try {
    $wc = New-Object System.Net.WebClient
    $wc.Headers.Add('User-Agent', 'ADDetector-Updater')
    $wc.Proxy = [System.Net.WebRequest]::DefaultWebProxy
    $wc.Proxy.Credentials = [System.Net.CredentialCache]::DefaultNetworkCredentials
    # 5 second timeout via async
    $task = $wc.DownloadStringTaskAsync('https://api.github.com/repos/ErenArslann/ADDetector/releases/latest')
    if ($task.Wait(5000)) {
        $release = $task.Result | ConvertFrom-Json
        $latest  = $release.tag_name
        if ($latest -and $latest -ne $script:CurrentVersion) {
            $zipAsset = $release.assets | Where-Object { $_.name -like '*.zip' } | Select-Object -First 1
            $script:UpdateAvailable = $true
            $script:LatestVersion   = $latest
            $script:LatestZipUrl    = if ($zipAsset) { $zipAsset.browser_download_url } else { '' }
            Write-LaunchLog 'INFO' "Update available: $latest"
        } else {
            Write-LaunchLog 'INFO' "Up to date: $script:CurrentVersion"
        }
    } else {
        Write-LaunchLog 'WARN' 'Update check timed out (non-fatal)'
    }
    $wc.Dispose()
} catch {
    Write-LaunchLog 'WARN' "Update check failed (non-fatal): $_"
}

# ── RSAT Check + Auto-Install ─────────────────────────────────────────────────
Add-Type -AssemblyName System.Windows.Forms

if (-not (Get-Command Get-ADUser -ErrorAction SilentlyContinue)) {
    Write-LaunchLog 'WARN' 'RSAT Active Directory module not found. Attempting install...'

    $installed = $false
    try {
        # Windows 10/11 - Add-WindowsCapability
        $cap = Get-WindowsCapability -Name 'Rsat.ActiveDirectory*' -Online -ErrorAction Stop |
               Where-Object { $_.State -ne 'Installed' }
        if ($cap) {
            foreach ($c in $cap) {
                Write-LaunchLog 'INFO' "Installing: $($c.Name)"
                Add-WindowsCapability -Name $c.Name -Online -ErrorAction Stop | Out-Null
            }
        }
        # Kontrol
        if (Get-Command Get-ADUser -ErrorAction SilentlyContinue) {
            $installed = $true
            Write-LaunchLog 'INFO' 'RSAT installed successfully.'
        }
    } catch {
        Write-LaunchLog 'ERROR' "RSAT auto-install failed: $_"
    }

    if (-not $installed) {
        Write-LaunchLog 'ERROR' 'RSAT could not be installed. Aborting.'
        [System.Windows.Forms.MessageBox]::Show(
            "RSAT Active Directory modulu bulunamadi ve otomatik kurulamadi.`n`nManuel kurulum:`nSettings > Optional Features > RSAT: Active Directory Domain Services and Lightweight Directory Tools`n`nLog: $logFile",
            'ADDetector - Gereksinim Eksik', 'OK', 'Warning') | Out-Null
        exit 1
    }
}

Write-LaunchLog 'INFO' 'RSAT check passed.'

# ── Launch MainForm ───────────────────────────────────────────────────────────
$mainForm = Join-Path $basePath 'MainForm.ps1'
if (-not (Test-Path $mainForm)) {
    Write-LaunchLog 'ERROR' "MainForm.ps1 not found: $mainForm"
    [System.Windows.Forms.MessageBox]::Show(
        "MainForm.ps1 bulunamadi.`nAranan: $mainForm",
        'ADDetector - Launch Error','OK','Error') | Out-Null
    exit 1
}

try {
    Write-LaunchLog 'INFO' 'Loading MainForm...'
    Set-ExecutionPolicy -Scope Process -ExecutionPolicy Bypass -Force -ErrorAction SilentlyContinue
    $mainFormContent = [System.IO.File]::ReadAllText($mainForm, [System.Text.Encoding]::UTF8)
    $sb = [ScriptBlock]::Create($mainFormContent)
    . $sb
    Write-LaunchLog 'INFO' 'MainForm exited cleanly.'
} catch {
    Write-LaunchLog 'ERROR' "Fatal: $_"
    [System.Windows.Forms.MessageBox]::Show(
        "ADDetector startup failed:`n`n$_`n`nLocation: $basePath`nLog: $logFile",
        'ADDetector - Fatal Error','OK','Error') | Out-Null
    exit 1
}
